  class SQLQueryValidator(allowedTables: Set[String], allowedOperations: Set[String]) {
    
    def validateQuery(query: String): Either[String, String] = {
      val normalizedQuery = query.trim.toLowerCase
      
      if (normalizedQuery.isEmpty) {
        return Left("Query cannot be empty")
      }
      
      val dangerousPatterns = List(
        "drop\\s+table",
        "drop\\s+database",
        "truncate\\s+table",
        "delete\\s+from",
        "insert\\s+into",
        "update\\s+",
        "create\\s+table",
        "alter\\s+table",
        "grant\\s+",
        "revoke\\s+",
        "set\\s+",
        "reset\\s+"
      )
      
      dangerousPatterns.foreach { pattern =>
        if (normalizedQuery.matches(s".*$pattern.*")) {
          return Left(s"Operation not allowed: $pattern")
        }
      }
      
      if (!normalizedQuery.startsWith("select") && 
          !normalizedQuery.startsWith("with") &&
          !normalizedQuery.startsWith("show") &&
          !normalizedQuery.startsWith("describe")) {
        return Left("Only SELECT, WITH, SHOW, and DESCRIBE queries are allowed")
      }
      
      val commentPatterns = List("--", "/\\*", "\\*/", "#")
      commentPatterns.foreach { pattern =>
        if (normalizedQuery.contains(pattern)) {
          return Left("Comments are not allowed in queries")
        }
      }
      
      if (normalizedQuery.split(";").length > 1) {
        return Left("Multiple statements are not allowed")
      }
      
      Right(query)
    }
    
    def validateTableAccess(plan: LogicalPlan): Either[String, Unit] = {
      val tables = extractTables(plan)
      val unauthorizedTables = tables.filterNot(allowedTables.contains)
      
      if (unauthorizedTables.nonEmpty) {
        Left(s"Access denied to tables: ${unauthorizedTables.mkString(", ")}")
      } else {
        Right(())
      }
    }
    
    private def extractTables(plan: LogicalPlan): Set[String] = {
      plan.collect {
        case UnresolvedRelation(tableIdentifier, _, _) => 
          tableIdentifier.table.toLowerCase
      }.toSet
    }
  }
  
  class SparkSQLExecutor(spark: SparkSession, validator: SQLQueryValidator) {
    
    def executeQuery(request: QueryRequest): QueryResponse = {
