              executionTimeMs = System.currentTimeMillis() - startTime
            )
          case Right(_) =>
        }
        
        val maxRows = request.maxRows.getOrElse(10000)
        val limitedDf = df.limit(maxRows)
        
        val schema = limitedDf.schema.fieldNames
        val rows = limitedDf.collect()
        
        val data = rows.map { row =>
          schema.zipWithIndex.map { case (fieldName, idx) =>
            val value = if (row.isNullAt(idx)) null else row.get(idx)
            fieldName -> value
          }.toMap
        }
        
        QueryResponse(
          success = true,
          data = Some(data),
          schema = Some(schema),
          rowCount = Some(rows.length),
          executionTimeMs = System.currentTimeMillis() - startTime
        )
        
      } match {
        case Success(response) => response
        case Failure(e: ParseException) =>
          QueryResponse(
            success = false,
            error = Some(s"SQL syntax error: ${e.getMessage}"),
            executionTimeMs = System.currentTimeMillis() - startTime
          )
        case Failure(e) =>
          QueryResponse(
            success = false,
            error = Some(s"Query execution failed: ${e.getMessage}"),
            executionTimeMs = System.currentTimeMillis() - startTime
          )
      }
    }
    
    def executeQueryWithTimeout(request: QueryRequest): QueryResponse = {
      import scala.concurrent._
      import scala.concurrent.duration._
      import ExecutionContext.Implicits.global
      
      val timeoutDuration = request.timeoutSeconds.getOrElse(300).seconds
      val queryFuture = Future {
        executeQuery(request)
      }
      
      Try {
        Await.result(queryFuture, timeoutDuration)
      } match {
        case Success(response) => response
        case Failure(_: TimeoutException) =>
          QueryResponse(
            success = false,
            error = Some(s"Query execution timeout after ${timeoutDuration.toSeconds} seconds"),
            executionTimeMs = timeoutDuration.toMillis
          )
        case Failure(e) =>
          QueryResponse(
            success = false,
            error = Some(s"Query execution error: ${e.getMessage}"),
            executionTimeMs = 0
          )
      }
    }
  }
  
